    ('omo_topbar', 'de', 'ade202b7f2c6304dc29e677cb6010c8fed6512397461062190598b6af227352a', '{\"topbar.bug.button\":{\"text\":\"Bug\"},\"topbar.bug.title\":{\"text\":\"Fehler melden\"},\"topbar.bug.unavailable_html\":{\"text\":\"<p>Formular nicht verfugbar.</p>\"},\"topbar.close\":{\"text\":\"Schliessen\"},\"topbar.drawer.default_title\":{\"text\":\"Seitenleiste\"},\"topbar.help.button\":{\"text\":\"Hilfe\"},\"topbar.help.fallback_label\":{\"text\":\"Hilfe\"},\"topbar.help.faq.description\":{\"text\":\"Zugriff auf die haufigsten Fragen mit einer Suche, um die passende Antwort schnell zu finden.\"},\"topbar.help.faq.label\":{\"text\":\"FAQ\"},\"topbar.help.faq.title\":{\"text\":\"OMO-FAQ\"},\"topbar.help.pending_html\":{\"text\":\"<p>Inhalt folgt.</p>\"},\"topbar.help.tour.description\":{\"text\":\"Gefuhrte Tour durch die sichtbaren Funktionen auf dem Bildschirm mit einer Erklarung zu jeder Schaltflache und jeder Moglichkeit.\"},\"topbar.help.tour.label\":{\"text\":\"Gefuhrte Tour\"},\"topbar.help.tutorials.description\":{\"text\":\"Gezielte Schulungen, um Sicherheit und Kompetenzen bei der Nutzung der Software aufzubauen.\"},\"topbar.help.tutorials.label\":{\"text\":\"Tutorien\"},\"topbar.help.tutorials.title\":{\"text\":\"Tutorien\"},\"topbar.help.unavailable_html\":{\"text\":\"<p>Inhalt nicht verfugbar.</p>\"},\"topbar.load_error\":{\"text\":\"Fehler beim Laden\"},\"topbar.loading\":{\"text\":\"Wird geladen...\"},\"topbar.modal.default_title\":{\"text\":\"Bereich\"},\"topbar.profile.button\":{\"text\":\"Profil\"},\"topbar.profile.details.email\":{\"text\":\"E-Mail\"},\"topbar.profile.details.empty_value\":{\"text\":\"Nicht angegeben\"},\"topbar.profile.details.name\":{\"text\":\"Name\"},\"topbar.profile.details.username\":{\"text\":\"Benutzername\"},\"topbar.profile.edit_label\":{\"text\":\"Profil bearbeiten\"},\"topbar.profile.edit_title\":{\"text\":\"Ihr Profil\"},\"topbar.profile.summary_fallback\":{\"text\":\"Profilubersicht\"},\"topbar.search.advanced_hint\"