    ('omo_get_structure_panel', 'en', '089a5cffc56bd11a6620b9ebf7cf4992e5bb8fdf61ded0f236d7ade344eae85e', '{\"structure.actions.export\":{\"text\":\"Export\"},\"structure.actions.menu_aria\":{\"text\":\"Actions\"},\"structure.actions.print\":{\"text\":\"Print\"},\"structure.actions.share\":{\"text\":\"Share\"},\"structure.browser.generic_name\":{\"text\":\"this browser\"},\"structure.error.organization_access_denied\":{\"text\":\"Access denied to this organization.\"},\"structure.list.empty_search\":{\"text\":\"No node matches this search.\"},\"structure.list.properties.hide_aria\":{\"text\":\"Hide properties\"},\"structure.list.properties.show_aria\":{\"text\":\"Show properties\"},\"structure.list.search.placeholder\":{\"text\":\"Quick filter\"},\"structure.message.invalid\":{\"text\":\"Invalid structure.\"},\"structure.message.load_error\":{\"text\":\"Unable to load the structure.\"},\"structure.message.no_structure\":{\"text\":\"No structure is available for this organization.\"},\"structure.share.modal_title\":{\"text\":\"Share the structure\"},\"structure.view.toggle_label\":{\"text\":\"G   L\"},\"structure.warning.brave\":{\"text\":\"Brave seems to block the canvas readout used for graph navigation, probably because of its fingerprinting shield. List view has been enabled so you can keep navigating. You can also relax the shield for this site.\"},\"structure.warning.dismiss_aria\":{\"text\":\"Collapse this message\"},\"structure.warning.pixel_mismatch\":{\"text\":\"{browserName} blocks or alters the canvas readout used for graph navigation. List view has been enabled so you can keep navigating.\"},\"structure.warning.restore\":{\"text\":\"Browser info\"},\"structure.warning.unavailable\":{\"text\":\"The canvas readout used for graph navigation is not available in {browserName}. List view has been enabled so you can keep navigating.\"}}', 'machine_translated'),
    ('omo_get_structure_panel', 'de', '089a5cffc56bd11a6620b9ebf7cf4992e5bb8fdf61ded0f236d7ade344eae85e', '{\"structure.actions.export\":{\"text\":\"Exportieren\"},\"structure.actions.menu_aria\":{\"text\":\"Aktionen\"},\"structure.actions.print\":{\"text\":\"Drucken\"},\"structure.actions.share\":{\"text\":\"Teilen\"},\"structure.browser.generic_name\":{\"text\":\"dieser Browser\"},\"structure.error.organization_access_denied\":{\"text\":\"Zugriff auf diese Organisation verweigert.\"},\"structure.list.empty_search\":{\"text\":\"Kein Knoten entspricht dieser Suche.\"},\"structure.list.properties.hide_aria\":{\"text\":\"Eigenschaften ausblenden\"},\"structure.list.properties.show_aria\":{\"text\":\"Eigenschaften anzeigen\"},\"structure.list.search.placeholder\":{\"text\":\"Schnellfilter\"},\"structure.message.invalid\":{\"text\":\"Ungultige Struktur.\"},\"structure.message.load_error\":{\"text\":\"Die Struktur konnte nicht geladen werden.\"},\"structure.message.no_structure\":{\"text\":\"Fur diese Organisation ist keine Struktur verfugbar.\"},\"structure.share.modal_title\":{\"text\":\"Struktur teilen\"},\"structure.view.toggle_label\":{\"text\":\"G   L\"},\"structure.warning.brave\":{\"text\":\"Brave scheint das Auslesen des Canvas fur die grafische Navigation zu blockieren, wahrscheinlich wegen des Anti-Fingerprinting-Schutzes. Die Listenansicht wurde aktiviert, damit Sie weiter navigieren konnen. Sie konnen den Schutz fur diese Website auch lockern.\"},\"structure.warning.dismiss_aria\":{\"text\":\"Diese Meldung einklappen\"},\"structure.warning.pixel_mismatch\":{\"text\":\"{browserName} blockiert oder verandert das Auslesen des Canvas fur die grafische Navigation. Die Listenansicht wurde aktiviert, damit Sie weiter navigieren konnen.\"},\"structure.warning.restore\":{\"text\":\"Browserinfo\"},\"structure.warning.unavailable\":{\"text\":\"Das Auslesen des Canvas fur die grafische Navigation ist in {browserName} nicht verfugbar. Die Listenansicht wurde aktiviert, d